29	int SpaceCommand::prepare(int argc, char* const argv[]) {
30	    if (!CoreApi::IsReady() || !Android::IsSdkReady())
31	        return Command::FINISH;
32	
33	    options.check = false;
34	    options.flag = 0;
35	    options.verify = 0;
36	
37	    int opt;
38	    int option_index = 0;
39	    optind = 0; // reset
40	    static struct option long_options[] = {
41	        {"check",      no_argument,       0,  'c'},
42	        {"full-check", no_argument,       0,  'f'},
43	        {"app",        no_argument,       0,   1 },
44	        {"zygote",     no_argument,       0,   2 },
45	        {"image",      no_argument,       0,   3 },
46	        {"fake",       no_argument,       0,   4 },
47	        {0,            0,                 0,   0 },
48	    };
49	
50	    while ((opt = getopt_long(argc, argv, "cf",
51	                long_options, &option_index)) != -1) {
52	        switch (opt) {
53	            case 'c':
54	                options.check = true;
55	                break;
56	            case 'f':
57	                options.check = true;
58	                options.verify = JavaVerify::CHECK_FULL_BAD_OBJECT
59	                              | JavaVerify::CHECK_FULL_CONFLICT_METHOD
60	                              | JavaVerify::CHECK_FULL_REUSE_DEX_PC_PTR
61	                              | JavaVerify::CHECK_FULL_U_EXTENDS_RECORD;
62	                break;
63	            case 1:
64	                options.flag |= Android::EACH_APP_OBJECTS;
65	                break;
66	            case 2:
67	                options.flag |= Android::EACH_ZYGOTE_OBJECTS;
68	                break;
69	            case 3:
70	                options.flag |= Android::EACH_IMAGE_OBJECTS;
71	                break;
72	            case 4:
73	                options.flag |= Android::EACH_FAKE_OBJECTS;
74	                break;
75	        }
76	    }
77	    options.optind = optind;
78	
79	    if (!options.flag) {
80	        options.flag |= Android::EACH_APP_OBJECTS;
81	        options.flag |= Android::EACH_ZYGOTE_OBJECTS;
82	        options.flag |= Android::EACH_IMAGE_OBJECTS;
83	        options.flag |= Android::EACH_FAKE_OBJECTS;
84	    }
85	
86	    Android::Prepare();
87	    return Command::ONCHLD;
88	}
89	
90	int SpaceCommand::main(int argc, char* const argv[]) {
91	    if (options.check) {
92	        JavaVerify verify;
93	        verify.init(options.verify, options.flag);
94	        auto callback = [&](art::mirror::Object& object) -> bool {
95	            if (verify.isEnabled()) verify.verify(object);
96	            return false;
97	        };
98	        Android::ForeachObjects(callback, options.flag, true);
99	        verify.verifyMethods();
100	    } else {
101	        art::Runtime& runtime = art::Runtime::Current();
102	        art::gc::Heap& heap = runtime.GetHeap();
103	
104	        LOGI(ANSI_COLOR_LIGHTRED "TYPE   REGION                  ADDRESS             NAME\n" ANSI_COLOR_RESET);
105	        for (const auto& space : heap.GetContinuousSpaces()) {
106	            art::gc::space::ContinuousSpace* sp = space.get();
107	            LOGI(" %2d  " ANSI_COLOR_LIGHTCYAN "[0x%" PRIx64 ", 0x%" PRIx64 ")  " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "  " ANSI_COLOR_LIGHTGREEN "%s\n" ANSI_COLOR_RESET,
108	                    sp->GetType(), sp->Begin(), sp->End(), sp->Ptr(), sp->GetName());
109	        }
110	
111	        for (const auto& space : heap.GetDiscontinuousSpaces()) {
112	            art::gc::space::DiscontinuousSpace* dsp = space.get();
113	            if (space->IsLargeObjectSpace()) {
114	                art::gc::space::LargeObjectSpace *sp = reinterpret_cast<art::gc::space::LargeObjectSpace *>(dsp);
115	                LOGI(" %2d  " ANSI_COLOR_LIGHTCYAN "[0x%" PRIx64 ", 0x%" PRIx64 ")  " ANSI_COLOR_LIGHTYELLOW "0x%" PRIx64 "  " ANSI_COLOR_LIGHTGREEN "%s\n" ANSI_COLOR_RESET,
116	                        sp->GetType(), sp->Begin(), sp->End(), sp->Ptr(), sp->GetName());
117	            } else {
118	                LOGI(" %2d  [0x0, 0x0)  0x%" PRIx64 "  %s\n", space->GetType(), space->Ptr(), space->GetName());
119	            }
120	        }
121	    }
122	    return 0;
123	}
124	
125	void SpaceCommand::usage() {
126	    LOGI("Usage: space [OPTION] [TYPE]\n");
127	    LOGI("Option:\n");
128	    LOGI("    -c, --check        check java space bad object.\n");
129	    LOGI("    -f, --full-check   check java space moreinfo.\n");
130	    LOGI("Type: {--app, --zygote, --image, --fake}\n");
131	    ENTER();
132	    LOGI("core-parser> space\n");
133	    LOGI("TYPE   REGION                  ADDRESS             NAME\n");
134	    LOGI("  5  [0x12c00000, 0x2ac00000)  0x75db0d608820  main space (region space)\n");
135	    LOGI("  0  [0x70209000, 0x7033d840)  0x75dbad608430  /system/framework/x86_64/boot.art\n");
136	    LOGI("  0  [0x704c2000, 0x704dfc88)  0x75dbad6086f0  /system/framework/x86_64/boot-core-libart.art\n");
137	    LOGI("  ...\n");
138	    ENTER();
139	    LOGI("core-parser> space --check --app\n");
140	    LOGI("ERROR: Region:[0x12c00000, 0x12c00018) main space (region space) has bad object!!\n");
141	}
